export function processScenario(scenario: {
  customer: { yearsWithMHPCO: number };
  steps: Array<{ op: string; items?: Array<{ type: string; cursed?: boolean; enchantment?: number }> }>;
}): ScenarioOutcome {
  return {
    results: scenario.steps.map((step, quoteIndex) => ({
      premium: calculateQuotePremium(step.items ?? [], scenario.customer.yearsWithMHPCO, quoteIndex),
    })),
  };
}
